{
  "name": "NovaTicket - Premium Booking Experience",
  "description": "A high-performance ticket booking prototype featuring a queue system, real-time seat selection, and secure payment flow with a sleek Red/Purple/Dark theme.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AppStep = 'HOME' | 'LOGIN' | 'QUEUE' | 'SEATING' | 'PAYMENT' | 'CONFIRMATION';

export interface Event {
  id: string;
  title: string;
  venue: string;
  date: string;
  image: string;
  priceRange: string;
}

export interface Seat {
  id: string;
  row: string;
  col: number;
  price: number;
  status: 'available' | 'reserved' | 'sold' | 'selected';
  zone: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
}

import React, { useState, useEffect } from 'react';
import { AppStep, Event, User } from './types';
import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import QueueRoom from './components/QueueRoom';
import SeatingPlan from './components/SeatingPlan';
import Payment from './components/Payment';
import Confirmation from './components/Confirmation';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<AppStep>('HOME');
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [bookingTimer, setBookingTimer] = useState<number>(0);

  // Global back button handler
  const goBack = () => {
    switch (currentStep) {
      case 'LOGIN': setCurrentStep('HOME'); break;
      case 'QUEUE': setCurrentStep('HOME'); break;
      case 'SEATING': setCurrentStep('HOME'); break;
      case 'PAYMENT': setCurrentStep('SEATING'); break;
      default: setCurrentStep('HOME');
    }
  };

  useEffect(() => {
    let interval: any;
    if (bookingTimer > 0) {
      interval = setInterval(() => {
        setBookingTimer((prev) => (prev > 0 ? prev - 1 : 0));
      }, 1000);
    } else if (bookingTimer === 0 && currentStep === 'PAYMENT') {
        // Handle timeout logic if needed
    }
    return () => clearInterval(interval);
  }, [bookingTimer, currentStep]);

  const handleSelectEvent = (event: Event) => {
    setSelectedEvent(event);
    if (!user) {
      setCurrentStep('LOGIN');
    } else {
      setCurrentStep('QUEUE');
    }
  };

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    if (selectedEvent) {
      setCurrentStep('QUEUE');
    } else {
      setCurrentStep('HOME');
    }
  };

  const handleQueueFinished = () => {
    setCurrentStep('SEATING');
  };

  const handleSeatsConfirmed = (seats: string[]) => {
    setSelectedSeats(seats);
    setBookingTimer(600); // 10 minutes
    setCurrentStep('PAYMENT');
  };

  const handlePaymentSuccess = () => {
    setCurrentStep('CONFIRMATION');
  };

  return (
    <div className="min-h-screen flex flex-col bg-neutral-950 text-white">
      <Header 
        user={user} 
        currentStep={currentStep} 
        onBack={goBack} 
        onLogout={() => setUser(null)}
      />

      <main className="flex-1 overflow-y-auto pt-16">
        {currentStep === 'HOME' && <Home onSelectEvent={handleSelectEvent} />}
        {currentStep === 'LOGIN' && <Login onLogin={handleLoginSuccess} />}
        {currentStep === 'QUEUE' && <QueueRoom onFinished={handleQueueFinished} event={selectedEvent!} />}
        {currentStep === 'SEATING' && (
          <SeatingPlan 
            event={selectedEvent!} 
            onConfirm={handleSeatsConfirmed} 
          />
        )}
        {currentStep === 'PAYMENT' && (
          <Payment 
            event={selectedEvent!} 
            seats={selectedSeats} 
            timer={bookingTimer}
            onSuccess={handlePaymentSuccess}
          />
        )}
        {currentStep === 'CONFIRMATION' && <Confirmation event={selectedEvent!} seats={selectedSeats} />}
      </main>

      {/* Persistence Floating Help */}
      <button className="fixed bottom-6 right-6 w-12 h-12 bg-purple-600 rounded-full flex items-center justify-center shadow-lg hover:bg-purple-500 transition-colors z-50">
        <i className="fas fa-question text-white"></i>
      </button>
    </div>
  );
};

export default App;

