interface QueueProps {
  event: Event;
  onFinished: () => void;
}

const QueueRoom: React.FC<QueueProps> = ({ event, onFinished }) => {
  const [position, setPosition] = useState(1240);
  const [estimatedTime, setEstimatedTime] = useState(5); // minutes

  useEffect(() => {
    const timer = setInterval(() => {
      setPosition((prev) => {
        const next = prev - Math.floor(Math.random() * 50) - 10;
        if (next <= 0) {
          clearInterval(timer);
