import React, { useState, useEffect } from 'react';
import { Event, Seat } from '../types';

interface SeatingPlanProps {
  event: Event;
  onConfirm: (seats: string[]) => void;
}

const ROWS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
const COLS = Array.from({ length: 12 }, (_, i) => i + 1);

const SeatingPlan: React.FC<SeatingPlanProps> = ({ event, onConfirm }) => {
  const [seats, setSeats] = useState<Seat[]>([]);
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [activeZone, setActiveZone] = useState<string>('Standing A');

  // Initialize seats
  useEffect(() => {
    const initialSeats: Seat[] = [];
    ROWS.forEach(row => {
      COLS.forEach(col => {
        initialSeats.push({
          id: `${row}${col}`,
          row,
          col,
          price: row <= 'B' ? 12000 : row <= 'E' ? 7500 : 3500,
          status: Math.random() > 0.85 ? 'sold' : 'available',
          zone: row <= 'E' ? 'VIP Zone' : 'Standard Zone'
        });
      });
    });
    setSeats(initialSeats);

    // Simulate real-time bookings by others
    const interval = setInterval(() => {
      setSeats(prev => prev.map(seat => {
        if (seat.status === 'available' && Math.random() > 0.98) {
          return { ...seat, status: 'reserved' };
        }
        return seat;
      }));
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  const toggleSeat = (id: string) => {
    const seat = seats.find(s => s.id === id);
    if (!seat || seat.status === 'sold' || seat.status === 'reserved') return;

    if (selectedSeats.includes(id)) {
      setSelectedSeats(prev => prev.filter(s => s !== id));
    } else {
      if (selectedSeats.length >= 6) {
        alert("Maximum 6 seats per transaction");
        return;
      }
      setSelectedSeats(prev => [...prev, id]);
    }
  };

  const totalPrice = selectedSeats.reduce((sum, id) => {
    const seat = seats.find(s => s.id === id);
    return sum + (seat?.price || 0);
  }, 0);

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] overflow-hidden">
      <div className="flex-1 overflow-auto p-4 md:p-8 flex flex-col items-center bg-[#050505]">
        <div className="w-full max-w-4xl">
          {/* Legend */}
          <div className="flex flex-wrap justify-center gap-6 mb-12 text-xs font-bold uppercase tracking-wider text-neutral-500">
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded bg-neutral-800 border border-white/10"></div>
              <span>Available</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded bg-rose-600 border border-rose-400"></div>
              <span>Selected</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded bg-neutral-900 border border-white/5 opacity-30"></div>
              <span>Occupied</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded bg-purple-600/50 animate-pulse"></div>
              <span>Reserved</span>
            </div>
          </div>

          {/* Stage Area */}
          <div className="w-full h-12 bg-neutral-900 rounded-t-[100px] border-t-4 border-rose-600/50 mb-16 flex items-center justify-center relative shadow-[0_-20px_50px_rgba(225,29,72,0.1)]">
            <span className="text-neutral-500 uppercase tracking-[0.3em] font-black text-sm">S T A G E</span>
          </div>

          {/* Seat Grid */}
          <div className="grid gap-3 select-none">
            {ROWS.map(row => (
              <div key={row} className="flex items-center justify-center gap-3">
                <div className="w-6 text-neutral-600 font-bold text-xs">{row}</div>
                <div className="flex gap-2">
                  {COLS.map(col => {
                    const id = `${row}${col}`;
                    const seat = seats.find(s => s.id === id);
                    const isSelected = selectedSeats.includes(id);
                    const isSold = seat?.status === 'sold';
                    const isReserved = seat?.status === 'reserved';

                    return (
                      <button
                        key={id}
                        onClick={() => toggleSeat(id)}
                        disabled={isSold || isReserved}
                        className={`
                          w-7 h-7 md:w-8 md:h-8 rounded-md text-[10px] font-bold transition-all duration-200 border
                          ${isSold ? 'bg-neutral-900 border-white/5 opacity-20 cursor-not-allowed' : ''}
                          ${isReserved ? 'bg-purple-900/30 border-purple-500/30 cursor-wait seat-glimmer' : ''}
                          ${!isSold && !isReserved && isSelected ? 'bg-rose-600 border-rose-400 text-white scale-110 shadow-[0_0_15px_rgba(225,29,72,0.5)] z-10' : ''}
                          ${!isSold && !isReserved && !isSelected ? 'bg-neutral-800 border-white/10 hover:border-rose-500 hover:text-rose-500 text-neutral-400' : ''}
                        `}
                      >
                        {col}
                      </button>
                    );
                  })}
                </div>
                <div className="w-6 text-neutral-600 font-bold text-xs text-right">{row}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Summary Footer bar - Real-time UI */}
      <div className="bg-neutral-900 border-t border-white/10 p-4 md:px-12 flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <span className="text-neutral-500 text-[10px] font-bold uppercase">Selected Seats</span>
            <div className="flex flex-wrap gap-2 mt-1">
              {selectedSeats.length > 0 ? selectedSeats.map(s => (
                <span key={s} className="bg-rose-600 text-white px-2 py-0.5 rounded text-xs font-bold">{s}</span>
              )) : (
                <span className="text-neutral-600 text-xs italic">No seats selected</span>
              )}
            </div>
          </div>
          <div className="h-10 w-[1px] bg-white/10 hidden md:block"></div>
          <div className="flex flex-col">
            <span className="text-neutral-500 text-[10px] font-bold uppercase">Total Amount</span>
            <span className="text-2xl font-black text-white">{totalPrice.toLocaleString()} <span className="text-xs font-normal">THB</span></span>
          </div>
        </div>

        <button 
          onClick={() => selectedSeats.length > 0 && onConfirm(selectedSeats)}
          disabled={selectedSeats.length === 0}
          className={`
            px-12 py-4 rounded-xl font-black uppercase tracking-widest transition-all
            ${selectedSeats.length > 0 ? 'bg-rose-600 hover:bg-rose-500 shadow-lg shadow-rose-900/30' : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'}
          `}
        >
          Confirm Reservation
        </button>
      </div>
    </div>
  );
};

export default SeatingPlan;

import React, { useState } from 'react';
import { Event } from '../types';

interface PaymentProps {
  event: Event;
  seats: string[];
  timer: number;
  onSuccess: () => void;
}

const Payment: React.FC<PaymentProps> = ({ event, seats, timer, onSuccess }) => {
  const [method, setMethod] = useState<'CARD' | 'QR' | 'WALLET'>('CARD');
  const [isProcessing, setIsProcessing] = useState(false);

  const formatTime = (seconds: number) => {
