        {currentStep === 'SEATING' && (
          <SeatingPlan 
            event={selectedEvent!} 
            onConfirm={handleSeatsConfirmed} 
          />
        )}
        {currentStep === 'PAYMENT' && (
          <Payment 
            event={selectedEvent!} 
            seats={selectedSeats} 
            timer={bookingTimer}
            onSuccess={handlePaymentSuccess}
          />
