import React, { useState, useEffect } from 'react';
import { Event, Seat } from '../types';

interface SeatingPlanProps {
  event: Event;
  onConfirm: (seats: string[]) => void;
}

const ZONE_CONFIG = [
  { name: 'VVIP (Row A-B)', price: 15000, color: 'bg-rose-600', rows: ['A', 'B'] },
  { name: 'VIP (Row C-E)', price: 9500, color: 'bg-purple-600', rows: ['C', 'D', 'E'] },
  { name: 'Standing A', price: 6500, color: 'bg-blue-600', rows: ['F', 'G'] },
  { name: 'Standard (Row H-J)', price: 3500, color: 'bg-neutral-600', rows: ['H', 'I', 'J'] }
];

const ROWS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
const COLS = Array.from({ length: 16 }, (_, i) => i + 1);

const SeatingPlan: React.FC<SeatingPlanProps> = ({ event, onConfirm }) => {
  const [seats, setSeats] = useState<Seat[]>([]);
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [hoveredSeat, setHoveredSeat] = useState<Seat | null>(null);

  useEffect(() => {
    const initialSeats: Seat[] = [];
    ROWS.forEach(row => {
      const zone = ZONE_CONFIG.find(z => z.rows.includes(row))!;
      COLS.forEach(col => {
        initialSeats.push({
          id: `${row}${col}`,
          row,
          col,
          price: zone.price,
          status: Math.random() > 0.88 ? 'sold' : 'available',
          zone: zone.name,
          color: zone.color
        });
      });
    });
    setSeats(initialSeats);

    const interval = setInterval(() => {
      setSeats(prev => prev.map(seat => {
        if (seat.status === 'available' && Math.random() > 0.99) {
          return { ...seat, status: 'reserved' };
        }
        return seat;
      }));
    }, 4000);

    return () => clearInterval(interval);
  }, []);

  const toggleSeat = (id: string) => {
    const seat = seats.find(s => s.id === id);
    if (!seat || seat.status === 'sold' || seat.status === 'reserved') return;

    if (selectedSeats.includes(id)) {
      setSelectedSeats(prev => prev.filter(s => s !== id));
    } else {
      if (selectedSeats.length >= 6) {
        alert("Maximum 6 seats per transaction");
        return;
      }
      setSelectedSeats(prev => [...prev, id]);
    }
  };

  const totalPrice = selectedSeats.reduce((sum, id) => {
    const seat = seats.find(s => s.id === id);
    return sum + (seat?.price || 0);
  }, 0);

  return (
