import React, { useState } from 'react';
import { Event, PerformanceRound } from '../types';

interface EventDetailProps {
  event: Event;
  onRoundSelect: (round: PerformanceRound) => void;
}

const EventDetail: React.FC<EventDetailProps> = ({ event, onRoundSelect }) => {
  const [selectedRoundId, setSelectedRoundId] = useState<string | null>(null);
  const [isFavorited, setIsFavorited] = useState(false);
  const [shareMessage, setShareMessage] = useState<string | null>(null);

  const handleFavorite = () => {
    setIsFavorited(!isFavorited);
  };

  const handleShare = async () => {
    const shareData = {
      title: event.title,
      text: `Check out ${event.title} at ${event.venue}!`,
      url: window.location.href,
    };

    const copyToClipboard = async () => {
      try {
        await navigator.clipboard.writeText(window.location.href);
        setShareMessage('Link copied to clipboard!');
        setTimeout(() => setShareMessage(null), 3000);
      } catch (err) {
        console.error('Failed to copy:', err);
      }
    };

    try {
      if (navigator.share && (navigator.canShare ? navigator.canShare(shareData) : true)) {
        await navigator.share(shareData);
      } else {
        await copyToClipboard();
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        console.error('Share failed, falling back to clipboard:', err);
        await copyToClipboard();
      }
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-12 animate-fadeIn relative">
      {/* Toast Notification for Share */}
      {shareMessage && (
        <div className="fixed top-20 right-4 bg-green-600 text-white px-6 py-3 rounded-xl shadow-2xl z-[100] animate-bounce flex items-center gap-2">
          <i className="fas fa-check-circle"></i>
          <span className="font-bold">{shareMessage}</span>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-12">
        {/* Left: Poster */}
        <div className="lg:w-1/3">
          <div className="sticky top-24">
            <img 
              src={event.image} 
              alt={event.title} 
              className="w-full aspect-[3/4] object-cover rounded-3xl shadow-2xl border border-white/10"
            />
            <div className="mt-6 flex gap-3">
              <button 
                onClick={handleShare}
                className="flex-1 bg-white/5 hover:bg-white/10 p-3 rounded-xl transition-all text-sm font-bold flex items-center justify-center gap-2 active:scale-95"
              >
                <i className="fas fa-share-nodes text-rose-500"></i> Share
              </button>
              <button 
                onClick={handleFavorite}
                className={`flex-1 p-3 rounded-xl transition-all text-sm font-bold flex items-center justify-center gap-2 active:scale-95 border ${
                  isFavorited 
                    ? 'bg-rose-600/20 border-rose-600 text-rose-500' 
                    : 'bg-white/5 border-transparent hover:bg-white/10 text-white'
                }`}
              >
                <i className={`${isFavorited ? 'fas' : 'heart'} fa-heart`}></i> 
                {isFavorited ? 'Favorited' : 'Favorite'}
              </button>
            </div>
          </div>
        </div>

        {/* Right: Info */}
        <div className="lg:w-2/3 space-y-8">
          <div>
            <div className="inline-block px-4 py-1 rounded-full bg-rose-600/20 text-rose-500 text-xs font-black uppercase tracking-widest mb-4">
              Now Selling
            </div>
            <h1 className="text-4xl md:text-6xl font-black mb-4 leading-tight">{event.title}</h1>
            <div className="flex flex-wrap gap-6 text-neutral-400">
              <div className="flex items-center gap-2">
                <i className="fas fa-calendar-day text-rose-500"></i>
                <span>{event.date}</span>
              </div>
              <div className="flex items-center gap-2">
                <i className="fas fa-location-dot text-rose-500"></i>
                <span>{event.venue}</span>
              </div>
              <div className="flex items-center gap-2">
                <i className="fas fa-ticket text-rose-500"></i>
                <span>{event.priceRange}</span>
              </div>
            </div>
          </div>

          <div className="bg-neutral-900/50 border border-white/5 rounded-3xl p-8 space-y-4">
            <h3 className="text-xl font-bold border-b border-white/5 pb-4">Event Description</h3>
            <p className="text-neutral-400 leading-relaxed">
              {event.description}
            </p>
          </div>

          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <h3 className="text-2xl font-bold flex items-center gap-3">
                <i className="fas fa-clock text-rose-600"></i>
                Select Performance Round
              </h3>
              <span className="text-neutral-500 text-xs font-black uppercase tracking-widest bg-white/5 px-3 py-1 rounded-full border border-white/5">
                {event.rounds.length} {event.rounds.length > 1 ? 'Show Dates' : 'Date Available'}
              </span>
            </div>

            <p className="text-neutral-400 text-sm italic">Please choose your preferred date and time below:</p>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {event.rounds.map((round) => (
                <button
                  key={round.id}
                  onClick={() => setSelectedRoundId(round.id)}
                  className={`
                    p-6 rounded-2xl border-2 text-left transition-all relative overflow-hidden group
                    ${selectedRoundId === round.id 
                      ? 'bg-rose-600/10 border-rose-600 shadow-[0_0_20px_rgba(225,29,72,0.2)]' 
                      : 'bg-black border-white/5 hover:border-white/20'}
                  `}
                >
                  <p className="text-[10px] font-black uppercase tracking-widest text-neutral-500 mb-1">Performance</p>
                  <h4 className="text-lg font-bold">{round.date}</h4>
                  <p className="text-rose-500 font-medium">Show time: {round.time}</p>
