            >
              {selectedRoundId ? 'Get Tickets Now' : 'Select a Round First'}
            </button>
            <p className="text-center text-xs text-neutral-500 mt-4">
              <i className="fas fa-shield-halved mr-2 text-emerald-500"></i> Verified Official Ticketing Platform
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

