  );
};

export default QueueRoom;

export type AppStep = 'HOME' | 'EVENT_DETAIL' | 'LOGIN' | 'QUEUE' | 'SEATING' | 'PAYMENT' | 'CONFIRMATION' | 'MY_BOOKINGS' | 'BROWSE_ALL' | 'LATEST_NEWS';

export interface PerformanceRound {
  id: string;
  date: string;
  time: string;
}

export interface Event {
  id: string;
  title: string;
  venue: string;
  date: string;
  image: string;
  priceRange: string;
  description: string;
  rounds: PerformanceRound[];
  stadiumLayoutType: 'STADIUM' | 'ARENA';
  category?: 'CONCERT' | 'FESTIVAL' | 'FAN_MEETING';
  status?: 'OPEN' | 'COMING_SOON' | 'SOLD_OUT';
}

/**
 * Represents a single seat in the venue's seating chart.
 */
export interface Seat {
  id: string;
  row: string;
  col: number;
  price: number;
  status: 'available' | 'sold' | 'reserved';
  zone: string;
  color: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
}

export interface Booking {
  orderId: string;
  event: Event;
  roundId: string; // Added to distinguish bookings between different dates
  seats: string[];
  totalPrice: number;
  bookingDate: string;
}

import React, { useState, useEffect } from 'react';
import { AppStep, Event, User, PerformanceRound, Booking } from './types';
import Header from './components/Header';
import Home from './components/Home';
import EventDetail from './components/EventDetail';
import Login from './components/Login';
import QueueRoom from './components/QueueRoom';
import SeatingPlan from './components/SeatingPlan';
import Payment from './components/Payment';
import Confirmation from './components/Confirmation';
import MyBookings from './components/MyBookings';
import BrowseAll from './components/BrowseAll';
import LatestNews from './components/LatestNews';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<AppStep>('HOME');
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [selectedRound, setSelectedRound] = useState<PerformanceRound | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [bookingTimer, setBookingTimer] = useState<number>(0);
  const [bookings, setBookings] = useState<Booking[]>([]);

  const goBack = () => {
    switch (currentStep) {
      case 'EVENT_DETAIL': setCurrentStep('BROWSE_ALL'); break;
      case 'LOGIN': setCurrentStep('EVENT_DETAIL'); break;
      case 'QUEUE': setCurrentStep('EVENT_DETAIL'); break;
      case 'SEATING': setCurrentStep('HOME'); break;
      case 'PAYMENT': setCurrentStep('SEATING'); break;
      case 'MY_BOOKINGS': handleReturnHome(); break;
      case 'BROWSE_ALL': setCurrentStep('HOME'); break;
      case 'LATEST_NEWS': setCurrentStep('HOME'); break;
      default: setCurrentStep('HOME');
    }
  };

  const handleLogout = () => {
    setUser(null);
    if (['QUEUE', 'SEATING', 'PAYMENT', 'MY_BOOKINGS'].includes(currentStep)) {
      setCurrentStep('LOGIN');
    }
  };

  useEffect(() => {
    let interval: any;
    if (bookingTimer > 0) {
      interval = setInterval(() => {
        setBookingTimer((prev) => (prev > 0 ? prev - 1 : 0));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [bookingTimer]);

  const handleSelectEvent = (event: Event) => {
    setSelectedEvent(event);
    setCurrentStep('EVENT_DETAIL');
  };

  const handleRoundSelected = (round: PerformanceRound) => {
    setSelectedRound(round);
    if (!user) {
      setCurrentStep('LOGIN');
    } else {
      setCurrentStep('QUEUE');
    }
  };

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    if (selectedEvent && selectedRound) {
      setCurrentStep('QUEUE');
    } else {
      setCurrentStep('HOME');
    }
  };

  const handleQueueFinished = () => {
    setCurrentStep('SEATING');
  };

  const handleSeatsConfirmed = (seats: string[]) => {
    setSelectedSeats(seats);
    setBookingTimer(600);
    setCurrentStep('PAYMENT');
  };

  const handlePaymentSuccess = () => {
    const newBooking: Booking = {
      orderId: `NV-${Math.floor(Math.random() * 90000000 + 10000000)}`,
      event: selectedEvent!,
      roundId: selectedRound!.id, // Store roundId for persistent seat blocking
      seats: selectedSeats,
      totalPrice: selectedSeats.length * 7500 + 200,
      bookingDate: new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
    };
    setBookings([newBooking, ...bookings]);
    setCurrentStep('CONFIRMATION');
  };

  const handleReturnHome = () => {
    setCurrentStep('HOME');
    setSelectedEvent(null);
    setSelectedRound(null);
    setSelectedSeats([]);
  };

  const handleGoToMyBookings = () => {
    setCurrentStep('MY_BOOKINGS');
    setSelectedEvent(null);
    setSelectedRound(null);
    setSelectedSeats([]);
  };

  const handleGoToBrowseAll = () => {
    setCurrentStep('BROWSE_ALL');
    setSelectedEvent(null);
    setSelectedRound(null);
    setSelectedSeats([]);
  };

  const handleTriggerLogin = () => {
    setCurrentStep('LOGIN');
  };

  return (
    <div className="min-h-screen flex flex-col bg-neutral-950 text-white">
      <Header 
        user={user} 
        currentStep={currentStep} 
        onBack={goBack} 
        onLogout={handleLogout}
        onLoginClick={() => setCurrentStep('LOGIN')}
        onMyBookings={handleGoToMyBookings}
        onHomeClick={handleReturnHome}
        onBrowseAll={() => setCurrentStep('BROWSE_ALL')}
        onLatestNews={() => setCurrentStep('LATEST_NEWS')}
      />

      <main className="flex-1 overflow-y-auto pt-16">
        {currentStep === 'HOME' && (
          <Home 
            onSelectEvent={handleSelectEvent} 
            onBrowseAll={() => setCurrentStep('BROWSE_ALL')}
            onLatestNews={() => setCurrentStep('LATEST_NEWS')}
          />
        )}
        {currentStep === 'BROWSE_ALL' && <BrowseAll onSelectEvent={handleSelectEvent} />}
        {currentStep === 'LATEST_NEWS' && <LatestNews onSelectEvent={handleSelectEvent} />}
        {currentStep === 'EVENT_DETAIL' && selectedEvent && (
          <EventDetail 
            event={selectedEvent} 
            user={user}
            onRoundSelect={handleRoundSelected} 
            onTriggerLogin={handleTriggerLogin}
          />
        )}
        {currentStep === 'LOGIN' && <Login onLogin={handleLoginSuccess} />}
        {currentStep === 'QUEUE' && <QueueRoom onFinished={handleQueueFinished} event={selectedEvent!} />}
        {currentStep === 'SEATING' && selectedEvent && selectedRound && (
          <SeatingPlan 
            event={selectedEvent} 
            selectedRound={selectedRound}
            bookings={bookings}
            onConfirm={handleSeatsConfirmed} 
          />
        )}
        {currentStep === 'PAYMENT' && selectedEvent && (
          <Payment 
            event={selectedEvent} 
            seats={selectedSeats} 
            timer={bookingTimer}
            onSuccess={handlePaymentSuccess}
          />
        )}
        {currentStep === 'CONFIRMATION' && selectedEvent && (
          <Confirmation 
            event={selectedEvent} 
            seats={selectedSeats} 
            onViewBookings={handleGoToMyBookings}
            onBookAnother={handleReturnHome}
          />
        )}
        {currentStep === 'MY_BOOKINGS' && (
          <MyBookings 
            bookings={bookings} 
            onExplore={handleGoToBrowseAll} 
            onBack={handleReturnHome}
          />
        )}
      </main>

      <button className="fixed bottom-6 right-6 w-12 h-12 bg-purple-600 rounded-full flex items-center justify-center shadow-lg hover:bg-purple-500 transition-colors z-50">
        <i className="fas fa-question text-white"></i>
      </button>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Event, Seat, Booking, PerformanceRound } from '../types';

interface SeatingPlanProps {
  event: Event;
  selectedRound: PerformanceRound;
  bookings: Booking[];
  onConfirm: (seats: string[]) => void;
}

const ZONE_CONFIG = [
  { name: 'VVIP (Row A-B)', price: 15000, color: 'bg-rose-600', borderColor: 'border-rose-400', rows: ['A', 'B'] },
  { name: 'VIP (Row C-E)', price: 9500, color: 'bg-purple-600', borderColor: 'border-purple-400', rows: ['C', 'D', 'E'] },
  { name: 'Standing A', price: 6500, color: 'bg-white', borderColor: 'border-neutral-300', rows: ['F', 'G'] },
  { name: 'Standard (Row H-J)', price: 3500, color: 'bg-neutral-500', borderColor: 'border-neutral-400', rows: ['H', 'I', 'J'] }
];

const ROWS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
const COLS = Array.from({ length: 16 }, (_, i) => i + 1);

const SeatingPlan: React.FC<SeatingPlanProps> = ({ event, selectedRound, bookings, onConfirm }) => {
  const [seats, setSeats] = useState<Seat[]>();
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [hoveredSeat, setHoveredSeat] = useState<Seat | null>(null);

  useEffect(() => {
    const initialSeats: Seat[] = [];

    // Find all seats already booked for this specific event and round
    const bookedSeatIds = new Set<string>();
    bookings.forEach(b => {
      if (b.event.id === event.id && b.roundId === selectedRound.id) {
        b.seats.forEach(s => bookedSeatIds.add(s));
      }
    });

    ROWS.forEach(row => {
      const zone = ZONE_CONFIG.find(z => z.rows.includes(row))!;
      COLS.forEach(col => {
        const seatId = `${row}${col}`;

        // If seat is in our permanent bookings list, it's 'sold'
        // Otherwise, keep a small random chance for mock data simulation
        const isPermanentlySold = bookedSeatIds.has(seatId);
        const isMockSold = !isPermanentlySold && Math.random() > 0.85;

        initialSeats.push({
          id: seatId,
          row,
          col,
          price: zone.price,
          status: (isPermanentlySold || isMockSold) ? 'sold' : 'available',
          zone: zone.name,
          color: zone.color
        });
      });
    });
    setSeats(initialSeats);

    // Simulate real-time status updates for OTHER users
    const interval = setInterval(() => {
      setSeats(prev => prev?.map(seat => {
        if (seat.status === 'available' && Math.random() > 0.98) {
          return { ...seat, status: 'reserved' };
        }
        if (seat.status === 'reserved' && Math.random() > 0.95) {
          return { ...seat, status: 'available' };
        }
        return seat;
      }));
    }, 3000);

    return () => clearInterval(interval);
  }, [event.id, selectedRound.id, bookings]);

  const toggleSeat = (id: string) => {
    const seat = seats?.find(s => s.id === id);
    if (!seat || seat.status === 'sold' || seat.status === 'reserved') return;

    if (selectedSeats.includes(id)) {
      setSelectedSeats(prev => prev.filter(s => s !== id));
    } else {
      if (selectedSeats.length >= 3) {
        alert("Maximum 3 seats per transaction");
        return;
      }
      setSelectedSeats(prev => [...prev, id]);
    }
  };

  const totalPrice = selectedSeats.reduce((sum, id) => {
    const seat = seats?.find(s => s.id === id);
    return sum + (seat?.price || 0);
  }, 0);

  if (!seats) return <div className="p-12 text-center text-neutral-500">Loading seating chart...</div>;

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] overflow-hidden bg-black">
      {/* Dynamic Status Legend */}
      <div className="bg-neutral-900 border-b border-white/10 px-6 py-4 flex flex-col gap-4">
        <div className="flex flex-wrap justify-center gap-6 md:gap-12">
           <div className="flex items-center gap-2">
             <div className="w-4 h-4 rounded bg-neutral-800 border border-white/5 flex items-center justify-center">
               <i className="fas fa-times text-[8px] text-neutral-600"></i>
             </div>
             <span className="text-[10px] font-bold uppercase text-neutral-500">Sold Out / Already Booked</span>
           </div>
           <div className="flex items-center gap-2">
             <div className="w-4 h-4 rounded bg-amber-500/20 border border-amber-500 animate-pulse"></div>
             <span className="text-[10px] font-bold uppercase text-neutral-500">Reserved (Holding)</span>
           </div>
           <div className="flex items-center gap-2">
             <div className="w-4 h-4 rounded bg-emerald-500 border border-emerald-300 shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
             <span className="text-[10px] font-bold uppercase text-neutral-500">Your Selection</span>
           </div>
        </div>

        <div className="h-[1px] w-full max-w-2xl mx-auto bg-white/5"></div>

        <div className="flex flex-wrap justify-center gap-6">
          {ZONE_CONFIG.map(zone => (
            <div key={zone.name} className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${zone.color} shadow-[0_0_10px_rgba(255,255,255,0.1)]`}></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-neutral-500 font-bold uppercase leading-none mb-1">{zone.name}</span>
                <span className="text-xs font-black">{zone.price.toLocaleString()} THB</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="flex-1 overflow-auto p-4 md:p-8 flex flex-col items-center custom-scrollbar">
        <div className="w-full max-w-5xl">
          {/* Stage Visualization */}
          <div className="relative mb-24 mt-8 flex justify-center">
            <div className="w-full max-w-3xl h-20 bg-gradient-to-b from-neutral-800 to-neutral-900 rounded-t-[150px] border-t-4 border-rose-600 flex items-center justify-center shadow-[0_-15px_60px_rgba(225,29,72,0.3)]">
              <div className="flex flex-col items-center">
                <span className="text-rose-600 uppercase tracking-[1em] font-black text-lg animate-pulse">S T A G E</span>
                <div className="flex gap-4 mt-2">
                   <div className="w-1 h-1 bg-rose-500 rounded-full animate-ping"></div>
                   <div className="w-1 h-1 bg-rose-500 rounded-full animate-ping delay-150"></div>
                   <div className="w-1 h-1 bg-rose-500 rounded-full animate-ping delay-300"></div>
                </div>
              </div>
            </div>
            {event.stadiumLayoutType === 'STADIUM' && (
              <div className="absolute top-20 left-1/2 -translate-x-1/2 w-16 h-24 bg-neutral-900 border-x-2 border-b-2 border-rose-600/30"></div>
            )}
          </div>

          {/* Performance Details Label */}
          <div className="text-center mb-8">
            <span className="text-[10px] text-rose-500 font-black uppercase tracking-[0.3em] bg-rose-500/10 px-6 py-2 rounded-full border border-rose-500/20">
              {selectedRound.date} @ {selectedRound.time}
            </span>
          </div>

          {/* Seating Arrangement */}
          <div className="grid gap-4 select-none perspective-1000 mb-20">
            {ROWS.map(row => (
              <div key={row} className="flex items-center justify-center gap-2 md:gap-4">
                <div className="w-8 text-neutral-600 font-black text-xs text-center">{row}</div>
                <div className="flex gap-1 md:gap-2">
                  {COLS.map((col, idx) => {
                    const id = `${row}${col}`;
                    const seat = seats.find(s => s.id === id);
                    if (!seat) return null;

                    const isSelected = selectedSeats.includes(id);
                    const isSold = seat.status === 'sold';
                    const isReserved = seat.status === 'reserved';
                    const zone = ZONE_CONFIG.find(z => z.rows.includes(row))!;

                    const isGap = idx === 3 || idx === 11;

                    return (
                      <React.Fragment key={id}>
                        {isGap && <div className="w-4 md:w-8"></div>}
                        <button
                          onMouseEnter={() => setHoveredSeat(seat)}
                          onMouseLeave={() => setHoveredSeat(null)}
                          onClick={() => toggleSeat(id)}
                          disabled={isSold || isReserved}
                          className={`
                            w-5 h-5 md:w-7 md:h-7 rounded-md text-[9px] font-bold transition-all duration-150 border relative flex items-center justify-center
                            ${isSold ? 'bg-neutral-900 border-white/5 cursor-not-allowed opacity-40' : ''}
                            ${isReserved ? 'bg-amber-500/20 border-amber-500 animate-pulse cursor-not-allowed shadow-[0_0_10px_rgba(245,158,11,0.3)]' : ''}
                            ${isSelected ? 'bg-emerald-500 border-emerald-300 text-white scale-110 shadow-[0_0_15px_rgba(16,185,129,0.7)] z-10' : ''}
                            ${!isSold && !isReserved && !isSelected ? `${zone.color} bg-opacity-20 ${zone.borderColor} hover:bg-opacity-40 text-white` : ''}
                          `}
                        >
                          {isSold ? (
                            <i className="fas fa-times text-neutral-700"></i>
                          ) : isReserved ? (
                            <i className="fas fa-user-clock text-amber-500 text-[7px]"></i>
                          ) : isSelected ? (
                            <i className="fas fa-check"></i>
                          ) : (
                            col
                          )}
                        </button>
                      </React.Fragment>
                    );
                  })}
                </div>
                <div className="w-8 text-neutral-600 font-black text-xs text-center">{row}</div>
              </div>
            ))}
          </div>

          {/* Detailed Floating Information */}
          {hoveredSeat && (
            <div className="fixed bottom-32 left-1/2 -translate-x-1/2 bg-neutral-900 border border-white/20 px-6 py-3 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] z-[60] animate-fadeIn pointer-events-none flex items-center gap-4">
              <div className={`w-4 h-4 rounded-full ${hoveredSeat.status === 'sold' ? 'bg-neutral-800' : hoveredSeat.status === 'reserved' ? 'bg-amber-500' : hoveredSeat.color}`}></div>
              <div className="flex flex-col">
                 <div className="flex items-center gap-2">
                    <span className="text-rose-500 font-black text-lg">Seat {hoveredSeat.id}</span>
                    <span className="text-[10px] bg-white/10 px-2 py-0.5 rounded text-neutral-400 font-bold uppercase">{hoveredSeat.zone}</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="text-white font-black text-sm">
                      {hoveredSeat.status === 'sold' ? 'UNAVAILABLE' : hoveredSeat.status === 'reserved' ? 'CURRENTLY RESERVED' : `${hoveredSeat.price.toLocaleString()} THB`}
                    </span>
                    {hoveredSeat.status === 'available' && <span className="text-emerald-500 text-[10px] font-bold">AVAILABLE</span>}
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Summary Footer bar */}
      <div className="bg-neutral-900 border-t border-white/10 p-6 md:px-12 flex flex-col md:flex-row items-center justify-between gap-6 z-50">
        <div className="flex flex-col md:flex-row items-center gap-8 w-full md:w-auto">
          <div className="flex flex-col items-center md:items-start">
            <span className="text-neutral-500 text-[10px] font-black uppercase tracking-widest mb-2">Selected ({selectedSeats.length}/3)</span>
            <div className="flex flex-wrap gap-2 justify-center">
              {selectedSeats.length > 0 ? selectedSeats.map(s => (
                <div key={s} className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-sm font-black shadow-lg shadow-emerald-900/20 animate-fadeIn">{s}</div>
              )) : (
                <span className="text-neutral-600 text-sm italic">Please select your seats</span>
              )}
            </div>
          </div>
          <div className="hidden md:block h-12 w-[1px] bg-white/10"></div>
          <div className="flex flex-col items-center md:items-start">
            <span className="text-neutral-500 text-[10px] font-black uppercase tracking-widest mb-1">Total Payable</span>
            <span className="text-3xl font-black text-white">{totalPrice.toLocaleString()} <span className="text-sm font-normal text-neutral-500">THB</span></span>
          </div>
        </div>

        <button 
          onClick={() => selectedSeats.length > 0 && onConfirm(selectedSeats)}
          disabled={selectedSeats.length === 0}
          className={`
            w-full md:w-auto px-16 py-4 rounded-2xl font-black uppercase tracking-[0.2em] transition-all text-lg
            ${selectedSeats.length > 0 
              ? 'bg-rose-600 hover:bg-rose-500 shadow-xl shadow-rose-900/40 active:scale-[0.97]' 
              : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'}
          `}
        >
          {selectedSeats.length > 0 ? 'Hold & Proceed' : 'Select Seats First'}
        </button>
      </div>
    </div>
  );
};

export default SeatingPlan;
